    template_id integer,
    deleted_at timestamp without time zone,
    service_category character varying(255),
    execution_duration character varying(128),
    insurance_amount numeric(14,2),
    min_workers integer,
    milestones_text text,
    warranty_text text,
    freight_responsible character varying(128),
    unloading_responsible character varying(128),
    project_number character varying(64),
    promoter character varying(255),
    work_start_date date,
    work_end_date date,
    duration_text character varying(128),
    payment_method character varying(64),
    payment_days integer,
    payment_method_other_text character varying(255),
    supplier_legal_rep_name character varying(255),
    supplier_legal_rep_dni character varying(64),
    deed_type character varying(128),
    notary_name character varying(255),
    notary_protocol character varying(64),
    deed_date date
);


