RIOR 4 43,35 173,40\nBABEROS 2 30,00 60,00\nCORONACIÓN 2 43,35 86,70\n493,50 18,45 9.105,08\nTOTAL CAPÍTULO 01 CUBIERTAS................................................................................. 65.738,27\nTOTAL............................................................................................................................ 65.738,27\nForma de pago: A convenir\nCondiciones Generales:\n· El suministro de energía eléctrica será por cuenta de la propiedad\n· Cualquier partida no presupuestada se valorará en obra\n· Estos precios no incluyen el IVA vigente (21%)\nConforme Cliente Conforme IMPULSA DESARROLLOS Y SERVICIOS, S.L.\nPágina 2	{"concept": null, "currency": "EUR", "due_date": null, "issue_date": null, "total_amount": 65738.27, "supplier_city": "Fortuna", "supplier_name": null, "invoice_number": null, "supplier_email": null, "supplier_phone": null, "supplier_tax_id": null, "supplier_address": "C/ Francisco Gomáriz Pagan, 3, Pol Ind Fortuna I", "supplier_country": "España", "supplier_postal_code": "30620"}	{"status": "success", "ocr_model": "deepseek-ocr:3b", "json_model": "qwen3-coder:30b", "finished_at": "2026-02-13T12:02:46.763990", "prompt_version": "v3", "comparative_totales": {"plazos": null, "garantias": null, "forma_pago": "A convenir", "total_ofertado_proveedor": 65738.27}, "comparative_detected": true, "comparative_json_model": "gpt-oss:20b"}	2026-02-11 13:30:55.700513
